SELECT/*상품정보로 유효한 정책정보를 들고온다.(약정포함)*/ DISTINCT C.SALE_PLCY_CD, C.SALE_PLCY_NM, AG.AGRM_TRM, RA.PAY_CL_CD, C.PRDT_SCTN_CD, ORG.ORGN_ID FROM MSP_SALE_PRDT_MST@DL_MSP A -- 정책 , CMN_INTM_MDL@DL_MSP B , MSP_SALE_PLCY_MST@DL_MSP C , MSP_RATE_MST@DL_MSP RA , MSP_SALE_RATE_MST@DL_MSP SA , MSP_SALE_ORGN_MST@DL_MSP ORG , MSP_SALE_AGRM_MST@DL_MSP AG WHERE 1=1 AND C.CNFM_YN ='Y' AND C.PLCY_SCTN_CD = 02 AND A.PRDT_ID = B.PRDT_ID AND SA.SALE_PLCY_CD = AG.SALE_PLCY_CD AND A.SALE_PLCY_CD = C.SALE_PLCY_CD AND A.SALE_PLCY_CD = SA.SALE_PLCY_CD AND RA.RATE_CD = SA.RATE_CD AND C.SALE_PLCY_CD = ORG.SALE_PLCY_CD AND TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN C.SALE_STRT_DTTM AND C.SALE_END_DTTM AND A.PRDT_ID = #{prdtId} AND RA.PAY_CL_CD = #{payClCd}
AND C.PRDT_SCTN_CD = #{prdtSctnCd}
AND ORG.ORGN_ID = #{orgnId} ORDER BY AGRM_TRM ASC

SELECT RATE_CD, --요금제 코드 RATE_NM, --요금제명 PAY_CL_CD, --선후불코드 CD_DSC, --선후불명 RATE_TYPE, --요금타입 RATE_DESC, --요금설명 VAT, -- 세금 BASE_AMT, --요금 DATA_TYPE AS DATA_TYPE_CODE, --데이터 타입 FREE_CALL_CNT, -- 무료통화 NW_IN_CALL_CNT, -- 망내통화 NW_OUT_CALL_CNT, -- 망외통화 FREE_SMS_CNT, -- SMS FREE_DATA_CNT, -- 데이터 SPRT_TP, --할인유형 GET_CODE_NM('F002',SPRT_TP)AS SPRT_TP_NM --할인유형이름 ,SALE_PLCY_CD FROM ( SELECT D.RATE_CD, D.RATE_NM, PAY_CL_CD, CD_DSC, D.RATE_TYPE , NVL(D.RMK, 0) AS RATE_DESC , D.BASE_AMT, (BASE_AMT*0.1) VAT, D.DATA_TYPE , D.FREE_CALL_CNT ,D.NW_IN_CALL_CNT,D.NW_OUT_CALL_CNT,D.FREE_SMS_CNT,D.FREE_DATA_CNT , B.SPRT_TP , B.SALE_PLCY_CD FROM MSP_SALE_ORGN_MST@DL_MSP A ,MSP_SALE_PLCY_MST@DL_MSP B ,MSP_SALE_RATE_MST@DL_MSP C ,MSP_RATE_MST@DL_MSP D ,CMN_GRP_CD_MST@DL_MSP E ,MSP_SALE_AGRM_MST@DL_MSP G WHERE TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN B.SALE_STRT_DTTM AND B.SALE_END_DTTM and A.SALE_PLCY_CD IN
#{item}
AND A.ORGN_ID = #{orgnId} AND B.CNFM_YN = 'Y' AND A.SALE_PLCY_CD = B.SALE_PLCY_CD AND A.SALE_PLCY_CD = C.SALE_PLCY_CD AND C.RATE_CD = D.RATE_CD AND D.APPL_END_DT = '99991231' AND E.GRP_ID = 'CMN0032' AND D.PAY_CL_CD = E.CD_VAL AND G.SALE_PLCY_CD = A.SALE_PLCY_CD ) GROUP BY RATE_CD, RATE_NM, PAY_CL_CD, CD_DSC, RATE_TYPE, RATE_DESC, VAT, BASE_AMT, DATA_TYPE , FREE_CALL_CNT, NW_IN_CALL_CNT, NW_OUT_CALL_CNT, FREE_SMS_CNT, FREE_DATA_CNT , SPRT_TP , SALE_PLCY_CD ORDER BY BASE_AMT ASC

mapper.update:
UPDATE NMCP_FAIL_USIM
SET AMD_DT = SYSDATE,
    AMD_ID = #{customerId}
WHERE USIM_NO = #{iccId}
